const secrets = $input.first().json.data || [];
const now = new Date();

const expiring = secrets
  .filter(s => s.expires_at)
  .map(s => {
    const exp = new Date(s.expires_at);
    const daysLeft = Math.ceil((exp - now) / (1000 * 60 * 60 * 24));
    return { ...s, daysLeft, expiresDate: exp.toISOString().split('T')[0] };
  })
  .filter(s => s.daysLeft <= 30 && s.daysLeft > -7)
  .sort((a, b) => a.daysLeft - b.daysLeft);

if (expiring.length === 0) {
  return [{ json: { skip: true, message: 'No credentials expiring within 30 days.' } }];
}

const critical = expiring.filter(s => s.daysLeft <= 1);
const urgent = expiring.filter(s => s.daysLeft > 1 && s.daysLeft <= 7);
const warning = expiring.filter(s => s.daysLeft > 7 && s.daysLeft <= 14);
const notice = expiring.filter(s => s.daysLeft > 14 && s.daysLeft <= 30);

let emoji = ':clock1:';
if (critical.length > 0) emoji = ':fire:';
else if (urgent.length > 0) emoji = ':rotating_light:';
else if (warning.length > 0) emoji = ':warning:';

const formatList = (items) => items.map(s => 
  `  \u2022 *${s.name}* (${s.service || 'unknown'}) — ${s.daysLeft <= 0 ? 'EXPIRED' : s.daysLeft + ' days'} (${s.expiresDate})`
).join('\n');

const parts = [`${emoji} *Credential Expiry Report*\n`];

if (critical.length > 0) parts.push(`:fire: *EXPIRED / EXPIRING TODAY:*\n${formatList(critical)}\n`);
if (urgent.length > 0) parts.push(`:rotating_light: *Expiring this week:*\n${formatList(urgent)}\n`);
if (warning.length > 0) parts.push(`:warning: *Expiring in 2 weeks:*\n${formatList(warning)}\n`);
if (notice.length > 0) parts.push(`:clock1: *Expiring within 30 days:*\n${formatList(notice)}\n`);

parts.push('_Rotate these before expiry to avoid outages. See `.env.secrets` for locations._');

return [{ json: { skip: false, message: parts.join('\n'), channel: 'C0ALVM4PAE7' } }];
